Below is a small, production-friendly in-memory cache in Go. It’s thread-safe, supports TTL per entry, optional max capacity with LRU eviction, and an optional background janitor for removing expired items. No external dependencies.

File: cache.go

package cache

import (
	"container/list"
	"sync"
	"time"
)

type CacheOptions struct {
	// Capacity is the max number of items to keep.
	// 0 or negative means unbounded.
	Capacity int

	// DefaultTTL applies when Set is called without an explicit TTL.
	// Zero means entries do not expire by default.
	DefaultTTL time.Duration

	// CleanupInterval runs a background janitor that removes expired items.
	// Zero disables the janitor.
	CleanupInterval time.Duration
}

type entry struct {
	key   string
	value any
	exp   time.Time // zero time means no expiration
}

type Cache struct {
	mu   sync.Mutex
	ll   *list.List                   // most-recently-used at front
	data map[string]*list.Element     // key -> *list.Element where Element.Value is *entry

	opts     CacheOptions
	stopCh   chan struct{}
	stopped  bool
	wg       sync.WaitGroup
	nowFunc  func() time.Time // for testing; defaults to time.Now
}

// New creates a new Cache with the given options.
func New(opts CacheOptions) *Cache {
	c := &Cache{
		ll:      list.New(),
		data:    make(map[string]*list.Element),
		opts:    opts,
		stopCh:  make(chan struct{}),
		nowFunc: time.Now,
	}
	if opts.CleanupInterval > 0 {
		c.wg.Add(1)
		go c.janitor(opts.CleanupInterval)
	}
	return c
}

// Set inserts or updates a value using the default TTL (if configured).
// To override TTL for this item, use SetWithTTL.
func (c *Cache) Set(key string, value any) {
	c.SetWithTTL(key, value, c.opts.DefaultTTL)
}

// SetWithTTL inserts or updates a value with a specific TTL.
// ttl <= 0 means no expiration for this entry.
func (c *Cache) SetWithTTL(key string, value any, ttl time.Duration) {
	c.mu.Lock()
	defer c.mu.Unlock()

	if c.stopped {
		return
	}

	if el, ok := c.data[key]; ok {
		en := el.Value.(*entry)
		en.value = value
		en.exp = c.calcExpiry(ttl)
		c.ll.MoveToFront(el)
		return
	}

	en := &entry{
		key:   key,
		value: value,
		exp:   c.calcExpiry(ttl),
	}
	el := c.ll.PushFront(en)
	c.data[key] = el

	if c.opts.Capacity > 0 && c.ll.Len() > c.opts.Capacity {
		c.evictLRU()
	}
}

// Get returns the value if present and not expired.
// It marks the item as most recently used.
func (c *Cache) Get(key string) (any, bool) {
	c.mu.Lock()
	defer c.mu.Unlock()

	el, ok := c.data[key]
	if !ok {
		return nil, false
	}

	en := el.Value.(*entry)
	if c.isExpired(en) {
		c.removeElement(el)
		return nil, false
	}

	c.ll.MoveToFront(el)
	return en.value, true
}

// Peek returns the value without affecting LRU order.
// Returns false if not present or expired.
func (c *Cache) Peek(key string) (any, bool) {
	c.mu.Lock()
	defer c.mu.Unlock()

	el, ok := c.data[key]
	if !ok {
		return nil, false
	}
	en := el.Value.(*entry)
	if c.isExpired(en) {
		c.removeElement(el)
		return nil, false
	}
	return en.value, true
}

// Delete removes a key if present.
func (c *Cache) Delete(key string) bool {
	c.mu.Lock()
	defer c.mu.Unlock()

	el, ok := c.data[key]
	if !ok {
		return false
	}
	c.removeElement(el)
	return true
}

// Len returns the number of items currently stored (including possibly expired ones
// if janitor is disabled and they haven't been accessed; they will be lazily removed).
func (c *Cache) Len() int {
	c.mu.Lock()
	defer c.mu.Unlock()
	return len(c.data)
}

// Close stops the background janitor (if running).
func (c *Cache) Close() {
	c.mu.Lock()
	if c.stopped {
		c.mu.Unlock()
		return
	}
	c.stopped = true
	close(c.stopCh)
	c.mu.Unlock()
	c.wg.Wait()
}

func (c *Cache) calcExpiry(ttl time.Duration) time.Time {
	if ttl <= 0 {
		return time.Time{}
	}
	return c.nowFunc().Add(ttl)
}

func (c *Cache) isExpired(en *entry) bool {
	if en.exp.IsZero() {
		return false
	}
	return c.nowFunc().After(en.exp)
}

func (c *Cache) evictLRU() {
	for c.opts.Capacity > 0 && c.ll.Len() > c.opts.Capacity {
		el := c.ll.Back()
		if el == nil {
			return
		}
		c.removeElement(el)
	}
}

func (c *Cache) removeElement(el *list.Element) {
	en := el.Value.(*entry)
	delete(c.data, en.key)
	c.ll.Remove(el)
}

func (c *Cache) janitor(interval time.Duration) {
	defer c.wg.Done()

	t := time.NewTicker(interval)
	defer t.Stop()

	for {
		select {
		case <-c.stopCh:
			return
		case <-t.C:
			c.cleanupExpired()
		}
	}
}

func (c *Cache) cleanupExpired() {
	now := c.nowFunc()

	c.mu.Lock()
	defer c.mu.Unlock()

	// Fast path: if empty, skip.
	if len(c.data) == 0 {
		return
	}

	for el := c.ll.Back(); el != nil; {
		prev := el.Prev()
		en := el.Value.(*entry)
		if !en.exp.IsZero() && now.After(en.exp) {
			c.removeElement(el)
		}
		el = prev
	}
}

