	c := cache.New(cache.CacheOptions{
		Capacity:        1000,
		DefaultTTL:      5 * time.Minute,
		CleanupInterval: 1 * time.Minute,
	})
	defer c.Close()

	c.Set("foo", "bar")                           // uses default TTL (5m)
