package cache

import (
	"sync"
	"time"
)

// Cache is a generic, in-memory, concurrent-safe cache with optional TTL per entry.
// Zero or negative TTL means "no expiration".
type Cache[K comparable, V any] struct {
	mu            sync.RWMutex
	data          map[K]entry[V]
	defaultTTL    time.Duration
	purgeInterval time.Duration

	stopCh chan struct{}
	wg     sync.WaitGroup
}

type entry[V any] struct {
	v   V
	exp time.Time // zero time means no expiration
}

// New creates a new Cache.
// defaultTTL: if > 0, used when Set is called with ttl <= 0.
// purgeInterval: how often expired entries are removed in the background; if <= 0, no janitor runs.
func New[K comparable, V any](defaultTTL, purgeInterval time.Duration) *Cache[K, V] {
	c := &Cache[K, V]{
		data:          make(map[K]entry[V]),
		defaultTTL:    defaultTTL,
		purgeInterval: purgeInterval,
		stopCh:        make(chan struct{}),
	}
	if purgeInterval > 0 {
		c.wg.Add(1)
		go c.janitor()
	}
	return c
}

// Set inserts or updates a key with value. If ttl > 0 it overrides defaultTTL for this item.
// If ttl <= 0 and defaultTTL <= 0, the item does not expire.
func (c *Cache[K, V]) Set(key K, value V, ttl time.Duration) {
	now := time.Now()
	var exp time.Time
	if ttl > 0 {
		exp = now.Add(ttl)
	} else if c.defaultTTL > 0 {
		exp = now.Add(c.defaultTTL)
	}
	c.mu.Lock()
	c.data[key] = entry[V]{v: value, exp: exp}
	c.mu.Unlock()
}

// Get returns the value and true if present and not expired; otherwise zero value and false.
// Expired items are removed on access.
func (c *Cache[K, V]) Get(key K) (V, bool) {
	var zero V
	now := time.Now()

	// Fast path with read lock.
	c.mu.RLock()
	e, ok := c.data[key]
	if !ok {
		c.mu.RUnlock()
		return zero, false
	}
	expired := !e.exp.IsZero() && now.After(e.exp)
	if !expired {
		val := e.v
		c.mu.RUnlock()
		return val, true
	}
	c.mu.RUnlock()

	// Upgrade to write lock to delete expired entry safely.
	c.mu.Lock()
	// Re-check after acquiring write lock.
	if e2, ok2 := c.data[key]; ok2 {
		if !e2.exp.IsZero() && now.After(e2.exp) {
			delete(c.data, key)
			c.mu.Unlock()
			return zero, false
		}
		val := e2.v
		c.mu.Unlock()
		return val, true
	}
	c.mu.Unlock()
	return zero, false
}

// Delete removes a key if present. Returns true if the key existed.
func (c *Cache[K, V]) Delete(key K) bool {
	c.mu.Lock()
	_, existed := c.data[key]
	if existed {
		delete(c.data, key)
	}
	c.mu.Unlock()
	return existed
}

// Len returns the number of entries (including any expired ones that haven't been purged yet).
func (c *Cache[K, V]) Len() int {
	c.mu.RLock()
	n := len(c.data)
	c.mu.RUnlock()
	return n
}

// PurgeExpired removes all expired entries immediately.
func (c *Cache[K, V]) PurgeExpired() {
	now := time.Now()
	c.mu.Lock()
	for k, e := range c.data {
		if !e.exp.IsZero() && now.After(e.exp) {
			delete(c.data, k)
		}
	}
	c.mu.Unlock()
}

// Close stops the background janitor (if running).
func (c *Cache[K, V]) Close() {
	if c.purgeInterval <= 0 {
		return
	}
	close(c.stopCh)
	c.wg.Wait()
}

func (c *Cache[K, V]) janitor() {
	defer c.wg.Done()
	t := time.NewTicker(c.purgeInterval)
	defer t.Stop()
	for {
		select {
		case <-t.C:
			c.PurgeExpired()
		case <-c.stopCh:
			return
		}
	}
}

