package cache

import (
	"sync"
	"time"
)

// Cache is a generic, thread-safe in-memory TTL cache.
// - Keys must be comparable.
// - Values can be any type.
// - defaultTTL <= 0 means entries do not expire by default.
// - cleanupInterval <= 0 disables the background janitor (expired items are removed on Get/Set).
type Cache[K comparable, V any] struct {
	mu              sync.RWMutex
	items           map[K]item[V]
	defaultTTL      time.Duration
	cleanupInterval time.Duration

	stopCh    chan struct{}
	stopped   chan struct{}
	closeOnce sync.Once
}

type item[V any] struct {
	value     V
	expiresAt time.Time // zero time means no expiration
}

// New creates a new cache with a default TTL and optional cleanup interval.
// If cleanupInterval > 0, a goroutine periodically removes expired items.
// Call Close() to stop the janitor when your service shuts down.
func New[K comparable, V any](defaultTTL, cleanupInterval time.Duration) *Cache[K, V] {
	c := &Cache[K, V]{
		items:           make(map[K]item[V]),
		defaultTTL:      defaultTTL,
		cleanupInterval: cleanupInterval,
		stopCh:          make(chan struct{}),
		stopped:         make(chan struct{}),
	}

	if cleanupInterval > 0 {
		go c.janitor()
	} else {
		// No janitor; mark as immediately stopped so Close() doesn't block.
		close(c.stopped)
	}

	return c
}

// Set stores a value using the cache's default TTL.
func (c *Cache[K, V]) Set(key K, value V) {
	c.SetWithTTL(key, value, c.defaultTTL)
}

// SetWithTTL stores a value with a specific TTL. ttl <= 0 means no expiration.
func (c *Cache[K, V]) SetWithTTL(key K, value V, ttl time.Duration) {
	var exp time.Time
	if ttl > 0 {
		exp = time.Now().Add(ttl)
	}

	c.mu.Lock()
	c.items[key] = item[V]{value: value, expiresAt: exp}
	c.mu.Unlock()
}

// Get retrieves a value. It returns (zeroValue, false) if missing or expired.
func (c *Cache[K, V]) Get(key K) (V, bool) {
	var zero V

	c.mu.RLock()
	it, ok := c.items[key]
	c.mu.RUnlock()
	if !ok {
		return zero, false
	}

	// Fast path if no expiration
	if it.expiresAt.IsZero() {
		return it.value, true
	}

	// Check expiration
	if time.Now().After(it.expiresAt) {
		// Expired: remove and return miss
		c.mu.Lock()
		// Re-check under write lock in case another goroutine updated it.
		if cur, still := c.items[key]; still {
			if cur.expiresAt.Equal(it.expiresAt) {
				delete(c.items, key)
			}
		}
		c.mu.Unlock()
		return zero, false
	}

	return it.value, true
}

// Delete removes a key if present.
func (c *Cache[K, V]) Delete(key K) {
	c.mu.Lock()
	delete(c.items, key)
	c.mu.Unlock()
}

// Len returns the number of entries currently held (may briefly include expired items until cleanup).
func (c *Cache[K, V]) Len() int {
	c.mu.RLock()
	n := len(c.items)
	c.mu.RUnlock()
	return n
}

// Close stops the background janitor (if running). Safe to call once.
func (c *Cache[K, V]) Close() {
	c.closeOnce.Do(func() {
		// If janitor is running, stop it; if not, stopped is already closed.
		select {
		case <-c.stopped:
			// already stopped
		default:
			close(c.stopCh)
			<-c.stopped
		}
	})
}

// janitor periodically purges expired items.
func (c *Cache[K, V]) janitor() {
	t := time.NewTicker(c.cleanupInterval)
	defer t.Stop()
	defer close(c.stopped)

	for {
		select {
		case <-t.C:
			c.purgeExpired()
		case <-c.stopCh:
			return
		}
	}
}

func (c *Cache[K, V]) purgeExpired() {
	now := time.Now()
	c.mu.Lock()
	for k, it := range c.items {
		if !it.expiresAt.IsZero() && now.After(it.expiresAt) {
			delete(c.items, k)
		}
	}
	c.mu.Unlock()
}
