package usersvc

import (
	"context"
	"time"

	"yourmodule/internal/cache"
)

type User struct {
	ID   string
	Name string
}

type UserStore interface {
	FindByID(ctx context.Context, id string) (User, error) // e.g., backed by MongoDB
}

type Service struct {
	store UserStore
	c     *cache.Cache[string, User]
}

func NewService(store UserStore) *Service {
	// Entries expire after 1 minute; cleanup runs every 30 seconds.
	c := cache.New[string, User](time.Minute, 30*time.Second)
	return &Service{store: store, c: c}
}

func (s *Service) Close() { s.c.Close() }

func (s *Service) GetUser(ctx context.Context, id string) (User, error) {
	if u, ok := s.c.Get(id); ok {
		return u, nil
	}
	u, err := s.store.FindByID(ctx, id)
	if err != nil {
		return User{}, err
	}
	s.c.Set(id, u) // uses default TTL
	return u, nil
}
